	public static ESeq loaded_modules() {
		EAtom[] mods;
		synchronized (infos) {
			mods = infos.keySet().toArray(new EAtom[0]);
		}
		ESeq out = ERT.NIL;
		for (int i = 0; i < mods.length; i++) {
			out = out.cons(mods[i]);
		}
		return out;
	}

	public static EAtom delete_module(EAtom module) {
		ModuleInfo mi = get_module_info(module);
		try {
			return mi.unload();
		} catch (ErlangException e) {
			throw e;
		} catch (Exception e) {
			throw new ErlangError(e);
		}
	}

	public static EModule get_loaded_module(EAtom module) {
		ModuleInfo mi = get_module_info(module);
		return mi.resident;
	}


	static final EAtom am__ = EAtom.intern("_");

	public EModuleManager() {
	}

	public static int trace_pattern(EPID self, EAtom mod, EAtom fun, EObject arg, EObject spec, EObject opts) {

		int argi = (arg == am__) ? -1 : arg.testSmall().asInt();

		ArrayList<ModuleInfo> mis = new ArrayList<ModuleInfo>();
		if (mod == am__) {
			ModuleInfo mi;
			synchronized (infos) {
				mis.addAll(infos.values());
			}
		} else {
			ModuleInfo mi = get_module_info(mod);
			mis.add(mi);
		}

		TraceOpts topts = new TraceOpts(self, spec, opts);

		int count = 0;
		for (int i = 0; i < mis.size(); i++) {
			ModuleInfo mi = mis.get(i);
			count += mi.trace_pattern(fun, argi, spec, topts);
		}

		return count;
	}

	static class TraceOpts {

		EMatchSpec match_spec = null;
		boolean is_global = true;
		EPID meta = null;

		TraceOpts(EPID self, EObject spec, EObject opts) {
			ESeq seq = spec.testSeq();
			if (seq != null) {
				match_spec = EMatchSpec.compile(seq);
			}

			ESeq o = opts.testSeq();
			if (o == null) return;

			while(!o.isNil()) {
				EObject v = o.head();
				o = o.tail();

				ETuple2 t2;
				if (v == am_global) {
					is_global = true;
				} else if (v == am_local) {
					is_global = false;
				} else if (v == am_meta) {
					meta = self;
				} else if ((t2=ETuple2.cast(v)) != null && t2.elem1 == am_meta) {
					meta = t2.elem2.testPID();
				}
			}
		}

	}
