        readProgressCallback = null;
        writeProgressCallback = null;
    }
    /**
     * Resets the input for loading the image. This method is mainly for
     * loading the image after reading upto READ_INFO and closing the input.
     * false can be passed for the keep_appxs param for the read following this
     * to retain the existing Image Header Information (Exif). A Runtime
     * exception results if the image is already read beyond INFO_SECTION.<p>
     *
     * The method uses inStream as the new input, sets readUpto to READ_NONE and
     * closes any internal Input Stream.
     * @param inStream New Input. If null then the previous input must have been
     * a file which will be used.
     */
    public void resetInput(InputStream inStream) {
        if(readUpto > READ_INFO)
            throw new RuntimeException("Restting Input not allowed if current input read beyond READ_INFO");
        if(inStream == null)
        {
            if(file == null)
                throw new RuntimeException("inStream null and no existing file to read from");
        }
        else
            file = null;
        closeInternalInputStream();
        this.inStream = inStream;
        readUpto = READ_NONE;
        unprocessed_marker = 0;
    }
    /**
     * Resets the input for loading the image. This method is mainly for
     * loading the image after reading upto READ_INFO and closing the input.
     * false can be passed for the keep_appxs param for the read following this
     * to retain the existing Image Header Information (Exif). A Runtime
     * exception results if the image is already read beyond INFO_SECTION.<p>
     *
     * The method uses file as the new input, sets readUpto to READ_NONE and
     * closes any internal Input Stream.
     * @param file New Input file.
     */
    public void resetInput(File file) {
        if(readUpto > READ_INFO)
            throw new RuntimeException("Restting Input not allowed if current input read beyond READ_INFO");
        closeInternalInputStream();
        this.file = file;
        inStream = null;
        readUpto = READ_NONE;
        unprocessed_marker = 0;
    }
