            if (valid) {
                readcounter = 0;
                writecounter = 0;
                if (file == null) {
                    if (inStream != null)
                        return inStream;
                    else
                        valid = false;
                } else {
                    return new BufferedInputStream(new FileInputStream(file));
                }
            }
        } catch(FileNotFoundException e) {
            valid = false;
        }
        return null;
    }
