    /**
     * Internal method which transforms the Image Header Info (Like Exif) and
     * updates the Appxs array.
     * This method essentially calls writeInfo on the stored imageInfo.
     * @param op The transform operation
     * @param options Options specifies how to manage exif or other header
     * content including embedded thumbnail transformation. Please pass a
     * bitwise OR (|) of the required set of OPT_XFORM_.. flags.
     * @param modifyImageInfo specifies if the instance of the imageInfo should
     * be modified or just the appxs array should be updated
     * @return Returns true if the method was successful or false if no data was
     * written by the imageInfo's writeInfo method. Note that the default
     * implementation provided in AbstractImageInfo is empty and this method
     * would fail unless the subclass overrides it which is done as of now only
     * in Exif.
     * @see AbstractImageInfo
     */
    protected boolean transformAppHeader(int op, int options, boolean modifyImageInfo)
    {
        boolean retVal = false;
        if (imageinfo != null && appxs != null && appHdrIndex >= 0) {
          try
          {
            ByteArrayOutputStream buf = new ByteArrayOutputStream(2*1024);
            /* TODO: Put in BasicJpeg if required
            if (imageinfo instanceof Exif && artist != null) {
                Exif exif = ((Exif)imageinfo);
                Entry e = exif.getTagValue(Exif.ARTIST, true);
                // TODO: localization, put in resources
                if (e == null) {
                    e = new Entry ("Camera owner, "+artist);
                    exif.setTagValue(Exif.ARTIST, Exif.EXIFOFFSET, e, true);
                } else
                    e.setValue(0, "Camera owner, "+artist);
            }
            */
            // Write out 4 bytes for the marker
            buf.write(markerid);
            buf.write(markerid);
            imageinfo.writeInfo(appxs[appHdrIndex], buf, op, options, modifyImageInfo, frm_x, frm_y);
            int len = buf.size() - 4;
            if (len > 0) {
                byte appCode = appxs[appHdrIndex][1];
                appxs[appHdrIndex] = buf.toByteArray();
                appxs[appHdrIndex][0] = M_PRX;
                appxs[appHdrIndex][1] = appCode;
                bn2s(appxs[appHdrIndex], 2, len+2, 2);
                retVal = true;
            }
            else
                if(Log.debugLevel >= Log.LEVEL_WARNING)
                    System.err.println("Warning: transform: Unable to transform App Hdr possibly because the format is not fully supported");
            buf.close();
            buf = null;
          } catch(Exception e)
          {
              if(Log.debugLevel >= Log.LEVEL_ERROR)
                e.printStackTrace(System.err);
              throw new RuntimeException(e.getMessage());
          }
        }
        return retVal;
    }
    private void validateCropBounds(Rectangle bounds)
    {
        if(bounds.width <= 0 || bounds.height <= 0 || bounds.x < 0 ||
           bounds.x >= frm_x || bounds.y < 0 || bounds.y >= frm_y)
            throw new ArrayIndexOutOfBoundsException("Invalid Crop Request");
        // Adjust origin to closest MCU boundary
        int xBoundary = getMCUWidth();
        int yBoundary = getMCUHeight();
        int rem;
        rem = bounds.x%xBoundary;
        cropBounds.x = bounds.x - rem;
        if(rem > xBoundary/2 && cropBounds.x + xBoundary < frm_x)
            cropBounds.x = cropBounds.x + xBoundary;
        rem = bounds.y%yBoundary;
        cropBounds.y = bounds.y - rem;
        if(rem > yBoundary/2 && cropBounds.y + yBoundary < frm_y)
            cropBounds.y = cropBounds.y + yBoundary;
        cropBounds.width = (cropBounds.x + bounds.width > frm_x)?
                            (frm_x - cropBounds.x):bounds.width;
        cropBounds.height = (cropBounds.y + bounds.height > frm_y)?
                            (frm_y - cropBounds.y):bounds.height;
    }
    /**
     * Checks if the current image is suitable for a perfect transform.
     * @return A bitwise OR (|) of the 2 flags IMPERFECT_X and IMPERFECT_Y.<p>
     *
     * IMPERFECT_X is set in the return value if the width (x origin in case op
     * is CROP) has to be adjusted/trimmed.<p>
     *
     * IMPERFECT_Y is set in the return value if the height (y origin in case op
     * is CROP) has to be adjusted/trimmed.<p>
     *
     * Thus 0 means the transform will be perfect.<p>
     *
     * Note that though checkPerfect returns 0 depending on <b>op</b>, the
     * transformation operation either or both the image width and height need
     * not be a multiple of the MCU width/height.
     * @see #IMPERFECT_X
     */
    public int checkPerfect(int op, Rectangle cropBounds)
    {
        int retVal = 0;
        int xBoundary = getMCUWidth();
        int yBoundary = getMCUHeight();
        if(op == CROP)
        {
            if(cropBounds.x % xBoundary != 0)
                retVal |= IMPERFECT_X;
            if(cropBounds.y % yBoundary != 0)
                retVal |= IMPERFECT_Y;
        }
        if((op == ROT_270 || op == TRANSVERSE ||
           op == ROT_180 || op == FLIP_H) && frm_x%xBoundary != 0)
            retVal |= IMPERFECT_X;
        if((op == ROT_90 || op == TRANSVERSE ||
           op == ROT_180 || op == FLIP_V) && frm_y%yBoundary != 0)
            retVal |= IMPERFECT_Y;
        return retVal;
    }
