    /** This is a high level method for lossless transformation of JPEG image.
     * This method may be called multiple times before saving the image using
     * save.  The jpeg image must be fully read by LLJTran first.<p>
     *
     * Use this method for CROP operation.
     *
     * @param op One of operations, like CROP, or ROT_xxx
     * @param options Options specifies how to manage exif or other header
     * content including embedded thumbnail transformation. Please pass a
     * bitwise OR (|) of the required set of OPT_XFORM_.. flags.
     * @param bounds Crop bounds. This must be passed if op is CROP, ignored
     * otherwise. The x and y values of bounds must be within the image and are
     * adjusted to the closest MCU boundary. The width and height must be
     * positive, but are automatically limited to imageWidth-bounds.x and
     * imageHieght-bounds.y respectively.  The bounds Object passed is
     * unchanged.
     * @see #save(OutputStream, int)
     */
    public void transform(int op, int options, Rectangle bounds) {
        prevHuffOption = -1;
        if(readUpto < READ_ALL)
            throw new RuntimeException("Transform cannot be performed since No Jpeg has been successfully Read");
        if((options & OPT_XFORM_APPX) == 0)
            options &= ~OPT_XFORM_THUMBNAIL;
        if((options & OPT_XFORM_THUMBNAIL) != 0 && !appxs_read)
            if(Log.debugLevel >= Log.LEVEL_WARNING)
                System.err.println("Warning: Thumbnail transformation cannot be performed since keep_appxs was passed as false while reading");
        if(op == CROP)
            validateCropBounds(bounds);
        adjustImageParameters(op, options);
        switch(op) {
          case TRANSPOSE:
          case TRANSVERSE:
          case ROT_90:
          case ROT_270:
            transposeImageParameters();
            transposeQTable();
            break;
          case ROT_180:
          case FLIP_H:
          case FLIP_V:
          case NONE:
          default:
        }
        try
        {
            if((options & OPT_XFORM_APPX) != 0)
                transformAppHeader(op, options, true);
            writeDCT(null, op, options, 0, true);
        } catch(IOException e)
        {
            if(Log.debugLevel >= Log.LEVEL_ERROR) {
                System.err.println("Warning:transform: Exception while transforming Thumbnail: " + e.getMessage());
                e.printStackTrace(System.err);
            }
        }
    }
