    /**
     * This internal method is used for the Iterative version of the transform
     * and save methods. The main use of this method is to get an
     * IterativeWriter for use with InStreamFromIterativeWriter class to read
     * the transformed image directly from LLJTran instead of writing it out.
     *
     * @param outStream Output Stream to which the jpeg image should be written
     * @param op Specifies the transformation like NONE, ROT_90 etc
     * @param options Options specifies how to manage exif or other header
     * content including embedded thumbnail transformation and also the header
     * information to write. Please pass a bitwise OR (|) of the required set
     * of OPT_XFORM_.. and OPT_WRITE_.. flags.
     * @param bounds Crop bounds. This must be passed if op is CROP, ignored
     * otherwise. The x and y values of bounds must be within the image and are
     * adjusted to the closest MCU boundary. The width and height must be
     * positive, but are automatically limited to imageWidth-bounds.x and
     * imageHieght-bounds.y respectively.  The bounds Object passed is
     * unchanged.
     * @param restart_interval Specifies to write a restart marker every
     * restart_interval MCU block. No restart markers are written if this
     * parameter is passed as 0
     * @param pullDownMode If this parameter is true then memory is freed as the
     * jpeg is written, making the LLJTran useless after the call. This option
     * can be used in case the Object reading the image allocates memory in
     * increments so that the maximum memory requirement would come down which
     * is not the case with java's ImageReader which allocates the
     * memory in one stroke. Also using this option for operations which change
     * the orientation by 90 degrees (ROT_90, ROT_270, TRANSPOSE and TRANSVERSE)
     * is illegal and results in a Runtime Exception.
     * @return An instance of IterativeWriter. calls to the nextWrite method of
     * this would write the next few bytes of the image to outStream. Though
     * the return value is currently the LLJTran object(this) the code should
     * use the return value only since it is possible this may change in future
     * to support an LLJTran object writing in multiple threads.
     * @param custom_appx Class specifying type of custom marker. Not used in
     * LLJTran.
     *
     * @see mediautil.gen.directio.InStreamFromIterativeWriter InStreamFromIterativeWriter
     */
    protected IterativeWriter initWrite(OutputStream outStream, int op, int options,
                             Rectangle bounds, int restart_interval,
                             boolean pullDownMode, Class custom_appx)
    throws IOException {
        prevHuffOption = -1;
        iWriteVars.maxWriteRequest = 0;
        iWriteVars.minWriteRequest = 100000000;
        iWriteVars.restoreVars = true;
        iWriteVars.saveAppxs = null;
        boolean writeAppxs = ((options & OPT_WRITE_APPXS) != 0);
        if(op == NONE || !writeAppxs)
            options &= ~OPT_XFORM_APPX;
        if((options & OPT_XFORM_APPX) == 0)
            options &= ~OPT_XFORM_THUMBNAIL;
        if(readUpto < READ_ALL)
            throw new RuntimeException("Transform cannot be performed since No Jpeg has been successfully Read");
        if(op == CROP)
            validateCropBounds(bounds);
        if(!appxs_read)
        {
            if((options & OPT_XFORM_THUMBNAIL) != 0)
                if(Log.debugLevel >= Log.LEVEL_WARNING)
                    System.err.println("Warning:transform: Thumbnail transformation cannot be performed since keep_appxs was passed as false while reading");
            if(writeAppxs)
                if(Log.debugLevel >= Log.LEVEL_WARNING)
                    System.err.println("Warning:transform: Cannote write APPXS since keep_appxs was passed as false while reading");
        }
        if(op != NONE)
        {
            iWriteVars.svX = frm_x;
            iWriteVars.svY = frm_y;
            iWriteVars.svWidthMCU = widthMCU;
            iWriteVars.svHeightMCU = heightMCU;
            adjustImageParameters(op, options);
            switch(op) {
              case TRANSPOSE:
              case TRANSVERSE:
              case ROT_90:
              case ROT_270:
                transposeImageParameters();
                transposeQTable();
                break;
              case ROT_180:
              case FLIP_H:
              case FLIP_V:
              case NONE:
              default:
            }
            if((options & OPT_XFORM_APPX) != 0 && appxs != null && appHdrIndex >= 0)
            {
                iWriteVars.saveAppxs = appxs[appHdrIndex];
                transformAppHeader(op, options, false);
            }
        }
        return initWriteJpeg(outStream, op, null, options, custom_appx,
                      restart_interval, pullDownMode);
    }
    /**
     * This method should be called when using the initWrite method with
     * nextWrite in writing out the jpeg image. It ensures that the state of the
     * image is restored.
     * @param writer The writer that was obtained from the initWriter call
     */
    public void wrapupIterativeWrite(IterativeWriter writer) {
        // Restore Image details
        if(iWriteVars.state != IterativeWriteVars.WRITE_COMPLETE)
        {
            if(iWriteVars.restoreVars && iWriteVars.op != NONE)
            {
                switch(iWriteVars.op) {
                  case TRANSPOSE:
                  case TRANSVERSE:
                  case ROT_90:
                  case ROT_270:
                    transposeImageParameters();
                    transposeQTable();
                    break;
                  case ROT_180:
                  case FLIP_H:
                  case FLIP_V:
                  case NONE:
                  default:
                }
                if(iWriteVars.saveAppxs != null)
                    appxs[appHdrIndex] = iWriteVars.saveAppxs;
                frm_x = iWriteVars.svX;
                frm_y = iWriteVars.svY;
                widthMCU = iWriteVars.svWidthMCU;
                heightMCU = iWriteVars.svHeightMCU;
            }
            iWriteVars.freeMemory();
            iWriteVars.state = IterativeWriteVars.WRITE_COMPLETE;
        }
    }
