    public InputStream getThumbnailAsStream()
    {
        ByteArrayInputStream retVal = null;
        int offset, len;
        if(appxs != null && appHdrIndex >= 0 && imageinfo != null &&
           (offset = imageinfo.getThumbnailOffset()) > 0 &&
           (len = imageinfo.getThumbnailLength()) > 0)
            retVal = new ByteArrayInputStream(appxs[appHdrIndex], offset + 4,
                                              len);
        return retVal;
    }
    /**
     * Sets the Thumbnail in the Image Header Information (Exif). This works
     * currenlty only if the Image has an Exif header which has been read.
     * @param newThumbnailData The new Thumbnail image
     * @param startIndex start index of the image in newThumbnailData
     * @param len Length of the Thumbnail
     * @param thumbnailExt File extension of the Thumbnail as specified in
     * {@link mediautil.image.ImageResources}. Currently works only for jpeg/bmp
     * Thumbnails for Exif headers.
     * @return True if successful in setting the Thumbnail false otherwise.
     */
    public boolean setThumbnail(byte newThumbnailData[], int startIndex,
                                    int len, String thumbnailExt)
    throws IOException
    {
        boolean retVal = false;
        if(len > 45000)
            throw new IOException("Size of Thumbnail is greater than 45000 bytes");
        if(appxs != null && appHdrIndex >= 0 && imageinfo != null)
        {
            ByteArrayOutputStream buf = new ByteArrayOutputStream(2*1024);
            // Write out 4 bytes for the marker
            buf.write(markerid);
            buf.write(markerid);
            imageinfo.setThumbnail(newThumbnailData,
                        startIndex, len, thumbnailExt, buf);
            int bytesWritten = buf.size() - 4;
            if (bytesWritten > 0)
            {
                byte newAppxs[] = buf.toByteArray();
                newAppxs[0] = M_PRX;
                newAppxs[1] = appxs[appHdrIndex][1];
                bn2s(newAppxs, 2, newAppxs.length-2, 2);
                appxs[appHdrIndex] = newAppxs;
                retVal = true;
            }
        }
        return retVal;
    }
    /** Refreshes the appx information array corresponding to any changes done
