    }
    private boolean partialYMCU;
    private boolean partialXMCU;
    private void adjustImageParameters(int op, int options)
    {
        int xBoundary = getMCUWidth();
        int yBoundary = getMCUHeight();
        if(op == CROP)
        {
            frm_x = cropBounds.width;
            frm_y = cropBounds.height;
            widthMCU = (frm_x + xBoundary - 1)/xBoundary;
            heightMCU = (frm_y + yBoundary - 1)/yBoundary;
        }
        int yMCURem = frm_y%yBoundary;
        int xMCURem = frm_x%xBoundary;
        partialYMCU = yMCURem != 0;
        partialXMCU = xMCURem != 0;
        if((options & OPT_XFORM_TRIM) != 0)
        {
            if(partialYMCU && (op == ROT_90 || op == TRANSVERSE ||
               op == ROT_180 || op == FLIP_V) && heightMCU > 1)
            {
                partialYMCU = false;
                frm_y -= yMCURem;
                heightMCU--;
            }
            if(partialXMCU && (op == ROT_270 || op == TRANSVERSE ||
               op == ROT_180 || op == FLIP_H) && widthMCU > 1)
            {
                partialXMCU = false;
                frm_x -= xMCURem;
                widthMCU--;
            }
        }
    }
    /**
     * This internal method is used for saving the image after applying the
     * given transformation. The image is restored to the original state after
     * the completion of the method.
     *
     * @param os Output Stream to which the jpeg image should be written
     * @param op Specifies the transformation like NONE, ROT_90 etc
     * @param comment Jpeg comment to Save. If null no comment will be written.
     * If "" existing comment will be retained
     * @param options Options specifies how to manage exif or other header
     * content including embedded thumbnail transformation and also the header
     * information to write. Please pass a bitwise OR (|) of the required set
     * of OPT_XFORM_.. and OPT_WRITE_.. flags.
     * @param bounds Crop bounds. This must be passed if op is CROP, ignored
     * otherwise. The x and y values of bounds must be within the image and are
     * adjusted to the closest MCU boundary. The width and height must be
     * positive, but are automatically limited to imageWidth-bounds.x and
     * imageHieght-bounds.y respectively.  The bounds Object passed is
     * unchanged.
     * @param custom_appx Class specifying type of custom marker. Not used in
     * LLJTran.
     * @param restart_interval Specifies to write a restart marker every
     * restart_interval MCU block. No restart markers are written if this
     * parameter is passed as 0
     * @param pullDownMode If this parameter is true then memory is freed as the
     * jpeg is written making the LLJTran useless after the call. This option
     * can be used in case the Object reading the image allocates memory in
     * increments so that the maximum memory requirement would come down which
     * is not the case with java's ImageReader which allocates the Buffered
     * memory in one stroke. Also using this option for operations which change
     * the orientation by 90 degrees (ROT_90, ROT_270, TRANSPOSE and TRANSVERSE)
     * is illegal and results in a Runtime Exception.
     */
    protected void writeJpeg(OutputStream os, int op, String comment,
                             int options, Rectangle bounds, Class custom_appx,
                             int restart_interval, boolean pullDownMode)
        throws IOException {
        if(op == CROP)
            validateCropBounds(bounds);
        initWriteJpeg(os, op,  comment, options, custom_appx, restart_interval,
                      pullDownMode);
        iWriteVars.restoreVars = false;
        do ; while(nextWrite(10000000) == IterativeReader.CONTINUE);
        if(Log.debugLevel >= Log.LEVEL_INFO)
            System.out.println("0x"+Integer.toHexString(writecounter)+"("+writecounter+") byte(s) Written Successfully");
    }
    // If comment is null no comment will be written. If "" then existing
    // comment data if any will be written, else comment will be written.
    private IterativeWriter initWriteJpeg(OutputStream os, int op,
                    String comment, int options, Class custom_appx,
                    int restart_interval, boolean pullDownMode)
                  throws IOException {
        if(pullDownMode && (op == ROT_90 || op == ROT_270 || op == TRANSPOSE ||
                            op == TRANSVERSE) )
            throw new RuntimeException("PullDownMode not allowed for Vertical<->Horizontal transform: " + op);
        writecounter = 0;
        HuffGenerator lHuffGen = null;
        byte optimizeHuff = (byte) ((options & OPT_WRITE_OPTIMIZE_HUFF)==0?0:1);
        byte huffTables[] = null;
        iWriteVars.os = os;
        iWriteVars.op = op;
        iWriteVars.comment = comment;
        iWriteVars.options = options;
        iWriteVars.custom_appx = custom_appx;
        iWriteVars.restart_interval = restart_interval;
        iWriteVars.pullDownMode = pullDownMode;
        if (canBeProcessed) {
          if(prevHuffOption != optimizeHuff)
          {
            prevHuffOption = optimizeHuff;
            if(optimizeHuff != 0)
            {
                // Huffman tables are recalculated since there may be new coeffs
                // not present in the exisint Huffman Tables.
                if(huffGen == null)
                    huffGen = new HuffGenerator();
                huffGen.init();
                gatheringStats = true;
                // Dry Run to get frequency counts of DC/AC symbols to be encoded
                // No output is written. The transforming routines like
                // rotate90DCT called by writeDCT also honour gatheringStats
                // variable and do not actually modify the DCT array.
                try
                {
                    writeDCT(null, op, options, 0, false);
                } catch(IOException e)
                {
                    if(Log.debugLevel >= Log.LEVEL_ERROR) {
                        System.err.println("Totally Unexpected IOException: " + e.getMessage());
                        e.printStackTrace(System.err);
                    }
                }
                // Disable Stat gathering and enabling writeDCT to write output
                gatheringStats = false;
                lHuffGen = huffGen;
            }
            huffTables = generateHuffTables(lHuffGen); // Load the new Huffman tables
            if(lHuffGen != null)
                lHuffGen.freeMemory();
          }
        }
        iWriteVars.huffTables = huffTables;
        iWriteVars.state = IterativeWriteVars.WRITE_BEGIN;
        return this;
    }
    /**
     * Writes atleast the next numBytes bytes. initWrite should have been called
     * before. Usually this method will be called via the IterativeWriter
     * interface and need not be called directly on an LLJTran object.
     * 750 bytes is a good value of the minimum number of bytes that would be
     * written and also for the writeCushion by which the actual number of bytes
     * written may exceed numBytes. The application appx markers are split while
     * writing to take care of the numBytes passed but not the comments. So
     * long jpeg comments may cause a large number of bytes to be written.
     * @see #initWrite(OutputStream,int,int,Rectangle,int)
     * @see mediautil.gen.directio.InStreamFromIterativeWriter InStreamFromIterativeWriter
     * @return IterativeReader.CONTINUE in case the writing is not complete.
     * Returns IterativeReader.STOP on completion of write.
     * @exception IOException in case of any errors.
     */
    public int nextWrite(int numBytes) throws IOException {
        if(iWriteVars.state == IterativeWriteVars.WRITE_COMPLETE)
            throw new IllegalStateException("nextWrite Called without initialization or after write completion");
        if(numBytes > iWriteVars.maxWriteRequest)
            iWriteVars.maxWriteRequest = numBytes;
        if(numBytes < iWriteVars.minWriteRequest)
            iWriteVars.minWriteRequest = numBytes;
        OutputStream os = iWriteVars.os;
        int op = iWriteVars.op;
        String comment = iWriteVars.comment;
        int options = iWriteVars.options;
        int restart_interval = iWriteVars.restart_interval;
        int nextState = iWriteVars.state;
        int markCounter = writecounter;
        int remaining = numBytes;
        do {
            switch(nextState) {
              case IterativeWriteVars.WRITE_BEGIN:
                writeMarkerSOI(os);
                nextState = IterativeWriteVars.WRITE_COMMENTS;
                if((options & OPT_WRITE_APPXS) != 0)
                {
                    nextState = IterativeWriteVars.WRITE_APPXS;
                    writeNewMarker(os, iWriteVars.custom_appx);
                    initWriteMarkerAppXs();
                    break;
                }
                break;
              case IterativeWriteVars.WRITE_APPXS:
               // write format specific marker
                if(!writeNextMarkerAppXs(remaining))
                    nextState = IterativeWriteVars.WRITE_COMMENTS;
                break;
              case IterativeWriteVars.WRITE_COMMENTS:
                nextState = IterativeWriteVars.WRITE_DQT;
                if((options & OPT_WRITE_COMMENTS) != 0)
                {
                    if(comment == null || comment.length() == 0)
                        writeMarkerComment(os, out_comment, enc);
                    else
                        writeMarkerComment(os, comment, enc);
                    break;
                }
                // Else fallthrough to next state
              case IterativeWriteVars.WRITE_DQT:
                writeMarkerDQT(os);
                nextState = IterativeWriteVars.WRITE_DHT;
                break;
              case IterativeWriteVars.WRITE_DHT:
                writeMarkerDHT(os, iWriteVars.huffTables);
                writeMarkerDRI(os, restart_interval);
                nextState = canBeProcessed?IterativeWriteVars.WRITE_START:
                                           IterativeWriteVars.WRITE_COMPLETE;
                break;
              case IterativeWriteVars.WRITE_START:
                writeMarkerSOF0(os);
                writeMarkerSOS(os);
                initWriteDCT(os, op, options, restart_interval, false);
                nextState = IterativeWriteVars.WRITE_DCT;
                break;
              case IterativeWriteVars.WRITE_DCT:
                if(!writeNextDCT(remaining))
                {
                    writeMarkerEOI(os);
                    nextState = IterativeWriteVars.WRITE_COMPLETE;
                }
                break;
            }
            remaining = numBytes - (writecounter-markCounter);
        } while(remaining > 0 &&
                nextState != IterativeWriteVars.WRITE_COMPLETE);
        int retVal = IterativeReader.CONTINUE;
        if(nextState == IterativeWriteVars.WRITE_COMPLETE)
        {
            if(iWriteVars.pullDownMode)
                freeMemory();
            else
                wrapupIterativeWrite(this);
            retVal = IterativeReader.STOP;
        }
        iWriteVars.state = nextState;
        return retVal;
    }
