    }
    private static final int APPXS_NONE = 0;
    private static final int APPXS_JFIF = 1;
    private static final int APPXS_JFXX = 2;
    private static final int APPXS_EXIF = 3;
    private static final int APPXS_CIFF = 4;
    private static final int APPXS_FPXR = 4;
    private int processAppMarker(byte markerData[], int offset,
                    AbstractImageInfo imageinfo[], boolean retHandledAppHdr[])
        throws FileFormatException
    {
      boolean handledAppHdr = false;
      int markerType = APPXS_NONE;
        if (isSignature(markerData, offset, JFIF)) {
            markerType = APPXS_JFIF;
            // x'FF', APP0, length, identifier, version,
            // units, Xdensity, Ydensity, Xthumbnail, Ythumbnail, (RGB)n
            int version = bs2i(5, 2);
            int units = bs2i(7, 1);
            int xden = bs2i(8, 2);
            int yden = bs2i(10, 2);
            int x = bs2i(12, 1);
            int y = bs2i(13, 1);
            int thumbnailsize = 3*x*y;
            if (x>0 && y>0)
                if(Log.debugLevel >= Log.LEVEL_INFO)
                    System.out.println("Thumbnail "+x+"x"+y+" in APP0");
        } else if (isSignature(markerData, offset, JFXX.FORMAT)) {
            markerType = APPXS_JFXX;
            handledAppHdr = true;
        } else if (isSignature(markerData, offset, Exif.FORMAT)) {
            markerType = APPXS_EXIF;
            handledAppHdr = true;
        } else if ((isSignature(markerData, offset, CIFF.II) || isSignature(markerData, offset, CIFF.MM))
            && isSignature(markerData, offset+6, CIFF.FORMAT)) {
            markerType = APPXS_CIFF;
            handledAppHdr = true;
        } else if (isSignature(markerData, offset, FPXR))
            markerType = APPXS_FPXR;
        if(retHandledAppHdr != null)
            retHandledAppHdr[0] = handledAppHdr;
        if(imageinfo != null && handledAppHdr)
        {
            if(offset != 0)
            {
                // Create 0 offset based array since that is what ImageInfo
                // constructors expect.
                byte newData[] = new byte[markerData.length-offset];
                System.arraycopy(markerData, offset, newData, 0,
                                 markerData.length-offset);
                markerData = newData;
            }
            // TODO: Do not know if this is ok. Have tried only Exif which
            // does not use InputStream is
            ByteArrayInputStream is = new ByteArrayInputStream(markerData);
            switch(markerType)
            {
              case APPXS_JFXX:
                imageinfo[0] = new JFXX(is, markerData, readcounter, getName(),
                                        out_comment, this);
                break;
              case APPXS_EXIF:
                imageinfo[0] = new Exif(is, markerData, readcounter, getName(),
                                        out_comment, this);
                break;
              case APPXS_CIFF:
                imageinfo[0] = new CIFF(is, markerData, readcounter, getName(),
                                        out_comment, this);
                break;
              default:
                break;
            }
        }
        return markerType;
    }
    private String initReadInternal(int sections, boolean keep_appxs, boolean throwException)
    {
        // Needs to be set before return since it is used in finally block
        String retVal = null;
        sections &= ALL_SECTIONS;
        iReadVars.maxReadRequest = 0;
        iReadVars.minReadRequest = 100000000;
        iReadVars.sections = sections;
        iReadVars.keep_appxs = keep_appxs;
        iReadVars.throwException = throwException;
        if(unprocessed_marker == 0 && (sections & HEADER_SECTION) == 0 &&
           (sections & BODY_SECTION) != 0)
            retVal = "Attempt to Read only the Body section when Header has not been successfully read";
        out_comment = "";
        // comment_data = null;
        if (file != null)
            valid = file.isFile();
        else
            valid = inStream != null;
        if (retVal == null && !valid)
            retVal = "Invalid input: " + getName();
        if(xferDone)
            retVal = "Cannot Read Further, Input has been Transferred using xferInfo()";
        if(retVal == null)
        {
            InputStream is = currentStream;
            if(is == null)
                is = createInputStream();
            iReadVars.is = is;
            if (valid)
            {
                currentStream = is;
                valid = false;
                canBeProcessed = true; //22
            }
            else
                retVal = "Unable to Read from input: " + getName();
        }
        iReadVars.stage = IterativeReadVars.READING_STAGE;
        return retVal;
    }
    /**
     * This method is to be used for the Iterative version of the read method.
     * The main use of this method is to get an IterativeReader for use with
     * SplitInputStream and OutStreamToIterativeReader classes to Share the
     * Image File with another Object while reading or to save an image from
     * another Object (Say BufferedImage) directly to an LLJTran Object thus
     * reducing disk io.
     *
     * @param readUpto The section upto which to read. You can pass READ_ALL to
     * read the entire image or READ_INFO to read only the Image Header
     * Information (Exif) to modify and rewrite using
     * {@link #xferInfo(InputStream, OutputStream, int, int) xferInfo(..)} or READ_HEADER to
     * read the header information and decoding tables but not the image data.
     * You  can make subsequent calls to read/initRead,nextReads with READ_ALL
     * to complete reading the image provided you are not reading using directio
     * classes like SplitInputStream.
     * @param keep_appxs Specifies if Image Information Header (Exif) is to be
     * retained. This should be passed as true if it is later required to be
     * written out. Note that if this is passed as false existing Image
     * Information Header is unchanged.
     * @param throwException Specifies if an exception is to be thrown on
     * encountering an error during a call of nextRead(). If this parameter is
     * passed as true then an IOException is thrown which gets propogated. This
     * option is useful for use with OutStreamToIterativeReader where there is
     * no point in continuing to write without anybody to read. If this
     * parameter is passed as false then then on encountering an error the
     * nextRead() call sets the error message and returns IterativeReader.STOP.
     * The error can be retrieved later using getErrorMsg() call. This option
     * may be useful for use with SplitInputStream where the main Reader can
     * continue to read data even if the LLJTran subReader errors out.
     * @exception LLJTranException If there is an error in the readUpto
     * parameter passed.
     *
     * @see IterativeReader
     * @see mediautil.gen.directio.SplitInputStream SplitInputStream
     * @see mediautil.gen.directio.OutStreamToIterativeReader OutStreamToIterativeReader
     */
    public void initRead(int readUpto, boolean keep_appxs,
                         boolean throwException)
            throws LLJTranException
    {
      String msg = null;
        if(readUpto < READ_INFO || readUpto > READ_ALL)
            msg = "Error:read: Invalid value " + readUpto + " for parameter readUpto";
        else if(readUpto <= this.readUpto)
        {
            if(Log.debugLevel >= Log.LEVEL_WARNING)
                System.err.println("Warning:initRead: Have already read " + uptoName[this.readUpto] + ", Exitting without doing anything");
        }
        else if(unprocessedError != null)
            msg = unprocessedError;
        else
        {
            int sections = 0;
            if(this.readUpto < READ_INFO)
                sections = READ_INFO;
            if(readUpto >= READ_HEADER)
            {
                if(this.readUpto < READ_HEADER)
                    sections |= HEADER_SECTION;
                if(readUpto >= READ_ALL)
                    sections |= BODY_SECTION;
            }
            iReadVars.readUpto = readUpto;
            msg = initReadInternal(sections, keep_appxs, throwException);
            if(msg != null)
                msg = "Error:initRead: " + msg;
        }
        if(msg != null)
            throw new LLJTranException(msg);
    }
    private void wrapupIterativeRead() {
        this.readUpto = iReadVars.readUpto;
    }
    /**
     * Reads the Image from the File or InputStream specified in the
     * Constructor.
     *
     * @param readUpto The section upto which to read. You can pass READ_ALL to
     * read the entire image or READ_INFO to read only the Image Header
     * Information (Exif) to modify and rewrite using
     * {@link #xferInfo(InputStream, OutputStream, int, int) xferInfo(..)} or READ_HEADER to
     * read the header information and decoding tables but not the image data.
     * You  can make subsequent calls to read/initRead,nextReads with READ_ALL
     * to complete reading the image provided you are not reading using directio
     * classes like SplitInputStream.
     * @param keep_appxs Specifies if Image Information Header (Exif) is to be
     * retained. This should be passed as true if it is later required to be
     * written out. Note that if this is passed as false existing Image
     * Information Header is unchanged.
     */
    public void read(int readUpto, boolean keep_appxs) throws LLJTranException
    {
        initRead(readUpto, keep_appxs, false);
        try
        {
            do ; while(nextRead(10000000) == IterativeReader.CONTINUE);
        }
        catch(IOException e) {} // Do not expect an IOException since last parameter to initRead is false.
        String msg = getErrorMsg();
        if(msg != null)
            throw new LLJTranException(msg);
    }
    /**
     * Returns upto what stage the image has been read.
     * @return One of the READ_.. flags including READ_NONE if nothing has been
     * read successfully.
     */
    public int getReadUpto()
    {
        return readUpto;
    }
    /**
     * Reads atleast the next numBytes bytes. initRead should have been called
     * before. Usually this method will be called via the IterativeReader
     * interface.
     * 750 bytes is a good value of the minimum number of bytes that would be
     * read and also for the readCushion by which the actual number of bytes
     * read may exceed numBytes. The application appx markers are split while
     * reading to take care of the numBytes passed but not the comments. So
     * long jpeg comments may cause a large number of bytes to be read.
     * @return IterativeReader.CONTINUE in case the reading is not complete.
     * Returns IterativeReader.STOP on completion of read or in case of an
     * error. getErrorMsg() should be called to check for errors.
     * @exception IOException If there is an error and throwException was
     * initialized as true.
     * @see #initRead(int,boolean,boolean)
     * @see mediautil.gen.directio.SplitInputStream SplitInputStream
     * @see mediautil.gen.directio.OutStreamToIterativeReader OutStreamToIterativeReader
     */
    public int nextRead(int numBytes) throws IOException {
        // Needs to be set before return since it is used in finally block
        InputStream is = iReadVars.is;
        boolean keep_appxs = iReadVars.keep_appxs;
        int sections = iReadVars.sections;
        String msg = null;
        int len;
        int retVal = IterativeReader.CONTINUE;
        int remaining = numBytes, markCounter;
        int stage = iReadVars.stage;
        if(numBytes > iReadVars.maxReadRequest)
            iReadVars.maxReadRequest = numBytes;
        if(numBytes < iReadVars.minReadRequest)
            iReadVars.minReadRequest = numBytes;
        markCounter = readcounter;
        try {
markers:
            do
            {
                if(sections == 0)
                    break markers;
                if(unprocessedError != null)
                {
                    msg = unprocessedError;
                    break markers;
                }
                if(stage < IterativeReadVars.READING_STAGE ||
                   stage >= IterativeReadVars.DONE_STAGE)
                {
                    msg = "read: nextRead called without initRead or called after completion of read";
                    break markers;
                }
                if(stage == IterativeReadVars.READING_DCT_STAGE)
                    if(readNextDCT(remaining))
                        continue;
                    else
                        stage = IterativeReadVars.IMAGE_READ_STAGE;
                if(stage == IterativeReadVars.READING_APPX_STAGE)
                    if(readNextAppx(remaining))
                        continue;
                    else
                    {
                        stage = IterativeReadVars.READING_STAGE;
                        if (keep_appxs)
                        {
                            // In LLJTran ImageInfo is loaded only if
                            // keep_appxs is set. This is incompatible with
                            // BasicJpeg reading info section and appxs data
                            // separately.
                            addAppx();
                            appxs_read = true;
                            boolean handledAppHdr[] = new boolean[1];
                            if(sections == INFO_SECTION)
                                valid = true;
                            if(Log.debugLevel >= Log.LEVEL_DEBUG)
                                System.out.println("Signature "+new String(data, 0, 4));
                            AbstractImageInfo curImageInfo[] = null;
                            if( (sections & INFO_SECTION) != 0)
                                curImageInfo = new AbstractImageInfo[1];
                            int markerType = processAppMarker(data, 4, curImageInfo,
                                                handledAppHdr);
                            if(markerType == APPXS_NONE && imageinfo == null) {
                                len = data.length;
                                if(Log.debugLevel >= Log.LEVEL_DEBUG)
                                    System.out.println("unhandled APP marker "+Integer.toHexString(markerid[1])+ " length "+len+" data "+new String(data, 0, len));
                            }
                            if(curImageInfo != null && curImageInfo[0] != null)
                                imageinfo = curImageInfo[0];
                            if (handledAppHdr[0] && imageinfo != null
                                && keep_appxs)
                                appHdrIndex = appxs.length-1;
                            if(Log.debugLevel >= Log.LEVEL_DEBUG)
                                System.out.println("Image info "+imageinfo);
                        }
                    }
                if(unprocessed_marker == 0)
                {
                    if (is.read(markerid) != markerid.length) {
                        // Wrong length read for marker header
                        msg = "Unexpected End Of Input";
                        break markers;
                    }
                    readcounter+=markerid.length;
                }
                else
                {
                    markerid[0] = M_PRX;
                    markerid[1] = (byte)unprocessed_marker;
                    unprocessed_marker = 0;
                }
                if(stage == IterativeReadVars.IMAGE_READ_STAGE && (markerid[0] != M_PRX || markerid[1] != M_EOI))
                {
                    valid = true;
                    stage = IterativeReadVars.DONE_STAGE;
                    if(Log.debugLevel >= Log.LEVEL_WARNING)
                        System.err.println("Warning:read: Found Bytes 0x" + Integer.toHexString(markerid[0]) + ", 0x" + Integer.toHexString(markerid[1]) + " instead of EOI, Ignoring remaining input");
                    break markers;
                }
                if (markerid[0] != M_PRX) {
                    // Wrong start signature markerid[0]
                    if (readcounter == markerid.length) {
                        // try TIFF
                        intel = markerid[0] == 'I' && markerid[1] == 'I';
                        motorola = markerid[0] == 'M' && markerid[1] == 'M';
                        if (intel || motorola) {
                            data = new byte[6];
                            if (is.read(data) == data.length &&
                                ((intel && data[0] == 42 && data[1] == 0) ||
                                (motorola && data[1] == 42 && data[0] == 0))) {
                                readcounter += data.length;
                                imageinfo = new TiffExif(is, data, readcounter, getName(), intel, this);
                            }
                        } else if (markerid[0] == Flashpix.SIGNATURE[0] && markerid[1] == Flashpix.SIGNATURE[1]) { // try Flashpix
                            data = new byte[6];
                            if (is.read(data) == data.length &&
                                data[0] == Flashpix.SIGNATURE[2] && data[1] == Flashpix.SIGNATURE[3] &&
                                data[2] == Flashpix.SIGNATURE[4] && data[3] == Flashpix.SIGNATURE[5] &&
                                data[4] == Flashpix.SIGNATURE[6] && data[5] == Flashpix.SIGNATURE[7]
                                ) {
                                readcounter += data.length;
                                // disable flashpix
                                /*try {
                                imageinfo = new Flashpix(is, data, readcounter, getName());
                                } catch(FileFormatException ffe) {
                                }*/
                            }
                        }
                    }
                    valid = imageinfo != null;
                    canBeProcessed = false;
                    msg = "Not a Jpeg File";
                    break markers;
                }
                byte markercode = markerid[1];
                switch(markercode) {
                  case M_SOI:
                    // proceed to next marker
                    allocateTables();
                    break;
                  case M_APP0:
                  case M_APP0+1:
                  case M_APP0+2:
                  case M_APP0+3:
                  case M_APP0+4:
                  case M_APP0+5:
                  case M_APP0+6:
                  case M_APP0+7:
                  case M_APP0+8:
                  case M_APP0+9:
                  case M_APP0+10:
                  case M_APP0+11:
                  case M_APP12:
                  case M_APP12+1:
                  case M_APP12+2:
                  case M_APP12+3:
                    // application specific marker found, just skip it
                    initReadAppx(markercode);
                    stage = IterativeReadVars.READING_APPX_STAGE;
                    break;
                  case M_DQT:
                    if (sections == INFO_SECTION) {
                        valid = true;
                        data = markerid;
                        unprocessed_marker = markercode;
                        stage = IterativeReadVars.DONE_STAGE;
                        break markers;
                    }
                    len = readMarker(is);
                    int []wt1d, wt2d[];
                    int pos = 0;
                    int lim;
                    while(pos < len) {
                        int tabnum = q_prec.length;
                        wt1d = new int[tabnum+1];
                        System.arraycopy(q_ix, 0, wt1d, 0, tabnum);
                        q_ix = wt1d;
                        q_ix[tabnum] = data[pos] & 15;
                        wt1d = new int[tabnum+1];
                        System.arraycopy(q_prec, 0, wt1d, 0, tabnum);
                        q_prec = wt1d;
                        q_prec[tabnum] = ((data[pos++]>>4) & 15)==0?8:16;
                        wt2d = new int[tabnum+1][DCTSIZE2];
                        System.arraycopy(q_table, 0, wt2d, 0, tabnum);
                        q_table = wt2d;
                        lim = pos+DCTSIZE2;
                        if (lim > len) lim = len;
                        for(int i = 0; pos < lim; i++)
                            q_table[tabnum][i] = data[pos++] & 255;
                    }
                    break;
                  case M_DHT:
                    if (sections == INFO_SECTION) {
                        valid = true;
                        data = markerid;
                        unprocessed_marker = markercode;
                        stage = IterativeReadVars.DONE_STAGE;
                        break markers;
                    }
                    len = readDHT(is, 0);
                    break;
                  case M_SOF0:
                  case M_SOF1:
                    if (sections == INFO_SECTION) {
                        valid = true;
                        data = markerid;
                        if(Log.debugLevel >= Log.LEVEL_INFO)
                            System.out.println("Abandoned M_SOF0 "+M_SOF0+"   "+markerid[1]);
                        unprocessed_marker = markercode;
                        stage = IterativeReadVars.DONE_STAGE;
                        break markers;
                    }
                    len = readMarker(is);
                    frm_precision = data[0] & 255;
                    frm_x = bs2i(3, 2);
                    frm_y = bs2i(1, 2);
                    components_in_frame = data[5] & 255;
                    if(Log.debugLevel >= Log.LEVEL_INFO) {
                        System.out.println("Frame, precision "+frm_precision);
                        System.out.println("X= "+frm_x+", Y= "+frm_y);
                        System.out.println("Components "+components_in_frame+" ("+getLocationName()+")");
                    }
                    V = new int[components_in_frame];
                    H = new int[components_in_frame];
                    QT = new int[components_in_frame];
                    ID = new int[components_in_frame];
                    pos=6;
                    maxHi = maxVi = 0;
                    int sampling = 0;
                    mcusize = 0;
                    for(int i=0; i<components_in_frame; i++) {
                        ID[i] = data[pos++] & 255;
                        sampling =  ((sampling << 8) + (data[pos] & 255));
                        H[i] = (data[pos]>>4) & 15;
                        if (H[i] > maxHi)
                            maxHi = H[i];
                        V[i] = data[pos++] & 15;
                        if (V[i] > maxVi)
                            maxVi = V[i];
                        mcusize += H[i] * V[i];
                        QT[i] = data[pos++] & 255;
                    }
                    widthMCU = (frm_x + DCTSIZE*maxHi - 1) / (DCTSIZE*maxHi);
                    heightMCU = (frm_y + DCTSIZE*maxVi - 1) / (DCTSIZE*maxVi);
                    if(Log.debugLevel >= Log.LEVEL_INFO)
                        System.out.println("Size in MCU "+widthMCU+"x"+heightMCU);
                    break;
                  case M_SOF2:
                    len = readMarker(is);
                    if(Log.debugLevel >= Log.LEVEL_ERROR)
                        System.err.println("Progressive, Huffman not supported in "+" ("+getLocationName()+")");
                    canBeProcessed = false; //22
                    msg = "Progressive, Huffman not supported";
                    if ( (sections & BODY_SECTION) != 0)
                        addMarker(len, markercode);
                    break;
                  case M_SOF9:
                    len = readMarker(is);
                    if(Log.debugLevel >= Log.LEVEL_ERROR)
                        System.err.println("Extended sequential, arithmetic not supported"+" ("+getLocationName()+")");
                    canBeProcessed = false; //22
                    msg = "Extended sequential, arithmetic not supported";
                    if ( (sections & BODY_SECTION) != 0)
                        addMarker(len, markercode);
                    break;
                  case M_SOF10:
                    len = readMarker(is);
                    if(Log.debugLevel >= Log.LEVEL_ERROR)
                        System.err.println("Progressive, arithmetic not supported"+" ("+getLocationName()+")");
                    canBeProcessed = false; //22
                    msg = "Progressive, arithmetic not supported";
                    if ( (sections & BODY_SECTION) != 0)
                        addMarker(len, markercode);
                    break;
                  case M_SOF3:
                  case M_SOF5:
                  case M_SOF6:
                  case M_SOF7:
                  case M_JPG:
                  case M_SOF11:
                  case M_SOF13:
                  case M_SOF14:
                  case M_SOF15:
                    len = readMarker(is);
                    if(Log.debugLevel >= Log.LEVEL_ERROR)
                        System.err.println("One of the unsupported SOF markers:\n"+
                                       "Lossless, Huffman\n"+
                                       "Differential sequential, Huffman\n"+
                                       "Differential progressive, Huffman\n"+
                                       "Differential lossless, Huffman\n"+
                                       "Reserved for JPEG extensions\n"+
                                       "Lossless, arithmetic\n"+
                                       "Differential sequential, arithmetic\n"+
                                       "Differential progressive, arithmetic\n"+
                                       "Differential lossless, arithmetic"+" ("+getLocationName()+")");
                    canBeProcessed = false; //22
                    msg = "Unsupported SOF marker";
                    if ( (sections & BODY_SECTION) != 0)
                        addMarker(len, markercode);
                    break;
                  case M_SOS:
                    if((sections & BODY_SECTION) == 0)
                    {
                        valid = true;
                        unprocessed_marker = markercode;
                        stage = IterativeReadVars.DONE_STAGE;
                        break markers;
                    }
                    len = readMarker(is);
                    if (canBeProcessed) { //22
                        components_in_scan = data[0] & 255;
                        pos=1;
                        comp_ids = new int[components_in_scan];
                        dc_table = new int[components_in_scan];
                        ac_table = new int[components_in_scan];
                        for(int i=0; i<components_in_scan; i++) {
                            comp_ids[i] = data[pos++] & 255;
                            dc_table[i] = (data[pos]>>4) & 15;
                            ac_table[i] = data[pos++] & 15;
                        }
                        _Ss = data[pos++] & 255;
                        _Se = data[pos++] & 255;
                        _Ah= (data[pos]>>4) & 15;
                        _Al= data[pos] & 15;
                        initReadDCT();
                        stage = IterativeReadVars.READING_DCT_STAGE;
                    } else {
                        addMarker(len, markercode);
                        if(Log.debugLevel >= Log.LEVEL_WARNING)
                            System.err.println("Warning: Read raw dct");
                        readRawDCT(is);
                        valid = true;
                        break markers;
                    }
                    break;
                  case M_COM:
                    len = readMarker(is);
                    // comment_data = data;
                    if (out_comment.length() > 0)
                        out_comment += '\n';
                    try {
                        out_comment += new String(data, 0, len, enc);
                    } catch(UnsupportedEncodingException uee) {
                        out_comment += new String(data, 0, len);
                    } catch(NullPointerException npe) {
                          out_comment += new String(data, 0, len);
                    }
                    break;
                  case M_EOI:
                    valid = true;
                    stage = IterativeReadVars.DONE_STAGE;
                    break markers;
                  case M_DRI:
                    if (sections == INFO_SECTION) {
                        valid = true;
                        data = markerid;
                        unprocessed_marker = markercode;
                        stage = IterativeReadVars.DONE_STAGE;
                        break markers;
                    }
                    len = readMarker(is);
                    if (len != 2)
                        throw new IOException("Wrong length of DRI marker "+len+" ("+getLocationName()+")");
                    restart_interval = bs2i(0, 2);
                    if(Log.debugLevel >= Log.LEVEL_INFO)
                        System.out.println("Restart interval "+restart_interval);
                    break;
                  case M_PRX:
                    // skip 0xFF filling
                    break;
                  default:
                    len = readMarker(is);
                    if ((0xfffffff0 & markercode) == 0xfffffff0)
                        break markers; // it's MP3
                    else
                        if(Log.debugLevel >= Log.LEVEL_WARNING)
                            System.err.println("Unsupported marker "+Integer.toHexString(markercode)+" length "+len+" ("+getLocationName()+")");
                }
                if (markercode >= M_SOF2 && markercode <= M_SOF15 && markercode != M_DHT && markercode != M_JPG) {
                    frm_precision = data[0] & 255;
                    frm_x = bs2i(3, 2);
                    frm_y = bs2i(1, 2);
                    components_in_frame = data[5] & 255;
                }
            } while((remaining = numBytes - (readcounter - markCounter)) > 0);
            if( (sections & INFO_SECTION) != 0 && imageinfo == null)
                imageinfo = new JPEG(frm_x, frm_y, frm_precision*components_in_frame, this);
            if (valid) {
                if ((sections & BODY_SECTION) == 0) {
                    unprocessedError = msg;
                    msg = null;
                } else
                    if(Log.debugLevel >= Log.LEVEL_INFO)
                        System.out.println("0x"+Integer.toHexString(readcounter)+"("+readcounter+") byte(s) read in "+getName());
            }
        } catch(Exception e) { // NullPointerException, IOException
            valid = false;
            msg = "Unexpected Error encountered during Read";
            setException(e);
            if(Log.debugLevel >= Log.LEVEL_ERROR)
                e.printStackTrace(System.err);
        } finally {
            iReadVars.stage = stage;
            if(msg != null && (unprocessedError == null
                || unprocessedError.indexOf("Previous Error") != 0))
                unprocessedError = "Previous Error: " + msg;
            if(msg != null || stage == IterativeReadVars.DONE_STAGE)
                retVal = IterativeReader.STOP;
            if (retVal == IterativeReader.STOP && currentStream != null)
            {
                if(((sections & BODY_SECTION) != 0 || msg != null)
                   && currentStream != inStream)
                {
                    try {
                        currentStream.close();
                    } catch (IOException ioe) {
                        // can't do much
                    }
                    currentStream = null;
                }
            }
            if(stage == IterativeReadVars.DONE_STAGE)
                wrapupIterativeRead();
            setErrorMsg(msg);
            if(msg != null && iReadVars.throwException)
                throw new IOException("Image Read Error In LLJTran:: " + msg);
        }
        return retVal;
    }
    // Not used, but coded anyways
    /**
     * Internal method to read the image.
     *
     * @param sections The sections to read. This is a bitwise OR (|) of one or
     * more of the flags INFO_SECTION, HEADER_SECTION and BODY_SECTION.
     * @param keep_appxs Specifies if Image Information Header (Exif) is to be
     * retained. This should be passed as true if it is later required to be
     * written out. Note that if this is passed as false existing Image
     * Information Header is unchanged.
     */
    protected String readInternal(int sections, boolean keep_appxs) {
        String retVal = initReadInternal(sections, keep_appxs, false);
        if(retVal == null)
        {
            String savedMsg = getErrorMsg();
            setErrorMsg(null);
            try
            {
                do ; while(nextRead(10000000) == IterativeReader.CONTINUE);
            }
            catch(IOException e) {} // Do not expect an IOException since last parameter to initReadInternal is false.
            retVal = getErrorMsg();
            setErrorMsg(savedMsg);
        }
        return retVal;
    }
    /**
     * This method is for modifying only the Image Header Information (Exif)
     * without processing the actual image. If you read the image fully and
     * write it back the jpeg decoding tables and the DCT coefficients will be
     * read into memory and then written back which is not the case with this
     * method.<p>
     *
     * For using this method you first read the image upto READ_INFO or if you
     * want to process the jpeg comments also it would be better to read upto
     * READ_HEADER since jpeg comments sometimes appear after the decoding
     * tables. Then you make the necessary changes to the imageInfo and call
     * refreshAppx after which you call xferInfo to read the image again and
     * write it out with the changed header and or comments. Also note that
     * since READ_HEADER defers the errors due to unsupported jpeg formats like
     * Progressive jpeg you can use this method to process the Image Header
     * Information (Exif) and/or jpeg comments for those files as well.
     *
     * @param is Image input to change the Image Header Information. The image
     * marker sections are read one by one and copied to the output except the
     * Image Header Information and/or comments which can be either copied,
     * replaced by what is present in the LLJTran Object or removed. Once the
     * header is read the rest of the image is copied as it is.<p>
     *
     * This parameter can be null to indicate that LLJTran continue to read from
     * the internal input stream where it had stopped. Below are the
     * restrictions when passing it as null:
     * <ul>
     *   <li> The image should have been read only upto READ_INFO so that all the
     *        decoding tables can be copied as it is.
     *   <li> Since You can only read upto READ_INFO, in this case trying to
     *        modify the comments is not fool proof since the comments may not
     *        have been read.
     *   <li> You cannot pass RETAIN for the parameters appxsOption or
     *        commentOption since they have already been read.
     *   <li> If you pass REPLACE for the parameters appxsOption or
     *        commentOption and comments and appx headers are encountered in the
     *        internal input they are also written (It is quite possible to
     *        encounter comments after READ_INFO since comments might come after
     *        decoding tables, but should not be the case with appx markers. But
     *        still..)
     *   <li> The LLJTran Object cannot be used after this method the input is
     *        already consumed.
     * </ul>
     *
     * @param os Output to write the image to.
     * @param appxsOption One of RETAIN, REPLACE or REMOVE indicating whether
     * the application specific markers (appxs) including Image Header
     * Information like Exif are to be retained from the input <b>is</b> or
     * replaced with what is there in the LLJTran Object or be removed.
     * @param commentOption One of RETAIN, REPLACE or REMOVE indicating whether
     * the jpeg comment section is to be retained from the input <b>is</b> or
     * replaced with what is there in the LLJTran Object or be removed.
     * @see #read(int,boolean)
     * @see #getImageInfo()
     * @see Exif
     */
    public void xferInfo(InputStream is, OutputStream os, int appxsOption,
                         int commentOption) throws LLJTranException
    {
      String msg = null;
      int pendingMarker = 0;
      int jpegMarkers = 0;
      boolean internalTransfer = false;
        if(is == null)
        {
            pendingMarker = unprocessed_marker;
            if(readUpto == READ_INFO)
            {
                if(xferDone)
                    msg = "Cannot Read Further, Input has been Transferred using xferInfo()";
                if(appxsOption == RETAIN || commentOption == RETAIN)
                    msg = "Cannot Retain appxs or comments when tranferring from internal stream";
                is = iReadVars.is;
            }
            else
                msg = "Can transfer from internal stream only if previously read upto READ_INFO";
        }
        if(is == iReadVars.is)
        {
            xferDone = true;
            internalTransfer = true;
        }
        if(msg == null)
          try {
            writeMarkerSOI(os);
            if(appxsOption == REPLACE)
                writeMarkerAppXs(os);
            if(commentOption == REPLACE)
                writeMarkerComment(os, out_comment, enc);
            if(data.length < 1024)
                data = new byte[1024];
markers:
            do
            {
                if(pendingMarker == 0)
                {
                    if (is.read(markerid) != markerid.length) {
                        // Wrong length read for marker header
                        msg = "Unexpected End Of Input";
                        break markers;
                    }
                    if (markerid[0] != M_PRX)
                    {
                        msg = "Invalid Marker found";
                        break markers;
                    }
                }
                else
                {
                    markerid[0] = M_PRX;
                    markerid[1] = (byte)pendingMarker;
                    pendingMarker = 0;
                }
                byte markercode = markerid[1];
                switch(markercode) {
                  case M_SOI:
                    break;
                  case M_APP0:
                  case M_APP0+1:
                  case M_APP0+2:
                  case M_APP0+3:
                  case M_APP0+4:
                  case M_APP0+5:
                  case M_APP0+6:
                  case M_APP0+7:
                  case M_APP0+8:
                  case M_APP0+9:
                  case M_APP0+10:
                  case M_APP0+11:
                  case M_APP12:
                  case M_APP12+1:
                  case M_APP12+2:
                  case M_APP12+3:
                    xferMarker(is, os, markercode,
                            appxsOption != RETAIN &&
                            (appxsOption == REMOVE || !internalTransfer));
                    break;
                  case M_COM:
                    xferMarker(is, os, markercode,
                            commentOption != RETAIN &&
                            (commentOption == REMOVE || !internalTransfer));
                    break;
                  case M_DRI:
                    xferMarker(is, os, markercode, false);
                    break;
                  case M_PRX:
                    break;
                  case M_DQT:
                  case M_DHT:
                  case M_SOF0:
                  case M_SOF1:
                  case M_SOF2:
                  case M_SOF9:
                  case M_SOF10:
                  case M_SOF3:
                  case M_SOF5:
                  case M_SOF6:
                  case M_SOF7:
                  case M_JPG:
                  case M_SOF11:
                  case M_SOF13:
                  case M_SOF14:
                  case M_SOF15:
                    ++jpegMarkers;
                    xferMarker(is, os, markercode, false);
                    break;
                  case M_SOS:
                    if(jpegMarkers >= 3)
                    {
                        xferMarker(is, os, markercode, false);
                        xferData(is, os, -1);
                        os.flush();
                        break markers;
                    }
                    else
                        msg = "All Jpeg Markers not Encountered. A likely error";
                    break;
                  case M_EOI:
                    msg = "Unexpected EOI marker found";
                    break;
                  default:
                    if(Log.debugLevel >= Log.LEVEL_WARNING)
                        System.err.println("Warning: xferAppxs(): Unhandled Marker " + Integer.toHexString(markercode));
                    xferMarker(is, os, markercode, false);
                    break;
                }
            } while(msg == null);
          } catch(Exception e) { // NullPointerException, IOException
            msg = "Unexpected Error encountered during Read";
            if(Log.debugLevel >= Log.LEVEL_ERROR)
                e.printStackTrace(System.err);
          }
        if(internalTransfer)
            closeInternalInputStream();
        if(msg != null)
            throw new LLJTranException(msg);
    }
    /**
     * Closes the internal Input Stream in case LLJTran was constructed with a
     * File. Note that This does not close the InputStream if passed in the
     * constructor.
     */
    public void closeInternalInputStream()
    {
        if(inStream == null && currentStream != null)
        {
            try {
                currentStream.close();
            } catch (IOException ioe) {
            }
            currentStream = null;
            unprocessed_marker = 0;
        }
    }
