        }
        if (is.read(markerid) != markerid.length) {
            throw new FileFormatException("Wrong length read for marker header");
        }
        byte saveData[] = data;
        data = markerid;
        int len = bs2i(0, 2)-2;
        data = saveData;
        if(skip)
            skip(is, len);
        else
