        OutputStream os = iWriteVars.os;
        int pos = iWriteVars.currentAppxPos;
        int newPos;
        boolean retVal = false;
        int remaining = numBytes;
        if(appxs != null)
        {
            retVal = true;
            do
            {
                if(i >= appxs.length)
                {
                    retVal = false;
                    break;
                }
                if(remaining <= 0)
                    break;
                byte curAppxs[] = appxs[i];
                int len = curAppxs.length - pos;
                if(len > remaining)
                {
                    len = remaining;
                    newPos = pos + remaining;
                }
                else
                {
                    i++;
                    newPos = 0;
                }
                os.write(curAppxs, pos, len);
                pos = newPos;
                remaining -= len;
                writecounter += len;
            } while (true);
        }
        iWriteVars.currentAppx = i;
        iWriteVars.currentAppxPos = pos;
        if(i >= appxs.length)
            retVal = false;
        return retVal;
    }
