                        ? GetTypeInfoForSymbol(crefSymbols[0])
                        : CSharpTypeInfo.None;
                }
                var typeInfo = GetTypeInfoForNode(boundNode, boundNode, boundNodeForSyntacticParent: null);
                return typeInfo;
