                case BoundKind.PropertyGroup:
                    symbols = GetPropertyGroupSemanticSymbols(boundNode, boundNodeForSyntacticParent, binderOpt, out resultKind, out memberGroup);
                    break;
                case BoundKind.BadExpression:
                    {
