                        resultKind = expr.ResultKind;
                        if (expr.Syntax.Kind == SyntaxKind.ObjectCreationExpression)
                        {
                            if (resultKind == LookupResultKind.NotCreatable || expr.Type.IsDelegateType())
                            {
                                resultKind = LookupResultKind.Empty;
