	@BIF
	public static EObject cancel_timer(EObject ref)
	{
		// check arguments 
		ERef timer_ref = ref.testReference();
		if (timer_ref == null) throw ERT.badarg();

		long time_left = ETimerTask.cancel(timer_ref);

		if (time_left > 0) {
